using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using FL.NetModule;
public class Script {
    public static object Main() {
        var controllers = Object.FindObjectsOfType<AnimalController>();
        AnimalController dog = null;
        foreach (var c in controllers) {
            if (c.StateData != null && c.StateData.AnimalType == 1) { dog = c; break; }
        }
        if (dog == null) return "No Dog found";
        var sd = dog.StateData;
        var dogPos = dog.transform.position;
        var playerGo = GameObject.Find("[PlayerManager]");
        if (playerGo == null) return "PlayerManager GO null";
        var playerPos = playerGo.transform.position;
        float dx = playerPos.x - dogPos.x;
        float dz = playerPos.z - dogPos.z;
        float dist = Mathf.Sqrt(dx*dx + dz*dz);
        return $"Dog Entity={sd.EntityId} State={sd.AnimalState} FollowTarget={sd.FollowTargetId} DogPos=({dogPos.x:F1},{dogPos.y:F1},{dogPos.z:F1}) PlayerDist={dist:F1}m";
    }
}
